import { useState, useEffect } from "react";

const API_BASE = "http://localhost:3000";

// ── Helpers ──────────────────────────────────────────────────────────────────
const formatPrice = (v) =>
  Number(v).toLocaleString("pt-BR", { style: "currency", currency: "BRL" });

const formatMileage = (v) =>
  Number(v).toLocaleString("pt-BR") + " km";

// ── Sub-components ────────────────────────────────────────────────────────────
function Navbar() {
  const [scrolled, setScrolled] = useState(false);
  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener("scroll", onScroll);
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  return (
    <nav className={`navbar ${scrolled ? "navbar--scrolled" : ""}`}>
      <div className="navbar__brand">
        <span className="navbar__icon">◈</span>
        <span className="navbar__name">AutoVitrine</span>
      </div>
      <div className="navbar__links">
        <a href="#">Início</a>
        <a href="#">Anunciar</a>
        <a href="#">Conta</a>
      </div>
      <button className="btn btn--outline">Entrar</button>
    </nav>
  );
}

function HeroBanner() {
  return (
    <section className="hero">
      <div className="hero__bg">
        <div className="hero__circle hero__circle--1" />
        <div className="hero__circle hero__circle--2" />
        <div className="hero__grid" />
      </div>
      <div className="hero__content">
        <p className="hero__eyebrow">🚗 Marketplace de Automóveis</p>
        <h1 className="hero__title">
          O carro dos seus<br />
          <span className="hero__title--accent">sonhos está aqui.</span>
        </h1>
        <p className="hero__sub">
          Compre, venda e negocie veículos com segurança e transparência.
        </p>
      </div>
    </section>
  );
}

function FilterBar({ filters, setFilters, onSearch }) {
  return (
    <div className="filter-bar">
      <input
        className="filter-bar__input"
        placeholder="Marca ou modelo..."
        value={filters.search}
        onChange={(e) => setFilters({ ...filters, search: e.target.value })}
      />
      <input
        className="filter-bar__input"
        placeholder="Cidade / Estado"
        value={filters.location}
        onChange={(e) => setFilters({ ...filters, location: e.target.value })}
      />
      <select
        className="filter-bar__select"
        value={filters.transmission}
        onChange={(e) => setFilters({ ...filters, transmission: e.target.value })}
      >
        <option value="">Câmbio</option>
        <option value="Manual">Manual</option>
        <option value="Automático">Automático</option>
      </select>
      <select
        className="filter-bar__select"
        value={filters.sort}
        onChange={(e) => setFilters({ ...filters, sort: e.target.value })}
      >
        <option value="">Ordenar por</option>
        <option value="price_asc">Menor preço</option>
        <option value="price_desc">Maior preço</option>
        <option value="mileage_asc">Menor KM</option>
        <option value="newest">Mais recentes</option>
      </select>
      <button className="btn btn--primary" onClick={onSearch}>
        Buscar
      </button>
    </div>
  );
}

function VehicleCard({ vehicle }) {
  const thumb =
    vehicle.images && vehicle.images.length > 0
      ? `${API_BASE}/${vehicle.images[0].imageUrl}`
      : null;

  return (
    <article className="card">
      <div className="card__thumb">
        {thumb ? (
          <img src={thumb} alt={`${vehicle.brand} ${vehicle.model}`} />
        ) : (
          <div className="card__no-img">
            <span>🚗</span>
          </div>
        )}
        <span className="card__badge">{vehicle.transmission}</span>
      </div>
      <div className="card__body">
        <div className="card__top">
          <h3 className="card__title">
            {vehicle.brand} {vehicle.model}
          </h3>
          <span className="card__year">
            {vehicle.manufactureYear}/{vehicle.modelYear}
          </span>
        </div>
        <p className="card__engine">{vehicle.engine}</p>
        <p className="card__location">📍 {vehicle.location}</p>
        <div className="card__stats">
          <span className="card__stat">🛣 {formatMileage(vehicle.mileage)}</span>
        </div>
        <div className="card__footer">
          <span className="card__price">{formatPrice(vehicle.price)}</span>
          <button className="btn btn--primary btn--sm">Ver detalhes</button>
        </div>
      </div>
    </article>
  );
}

function SkeletonCard() {
  return (
    <article className="card card--skeleton">
      <div className="card__thumb skeleton-box" />
      <div className="card__body">
        <div className="skeleton-line skeleton-line--wide" />
        <div className="skeleton-line skeleton-line--mid" />
        <div className="skeleton-line skeleton-line--short" />
        <div className="skeleton-line skeleton-line--mid" />
      </div>
    </article>
  );
}

// ── Main Component ─────────────────────────────────────────────────────────────
export default function Home() {
  const [vehicles, setVehicles] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [filters, setFilters] = useState({
    search: "",
    location: "",
    transmission: "",
    sort: "",
  });

  const fetchVehicles = async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await fetch(`${API_BASE}/vehicles`);
      if (!res.ok) throw new Error("Erro ao carregar veículos.");
      const data = await res.json();
      setVehicles(Array.isArray(data) ? data : data.vehicles ?? []);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchVehicles();
  }, []);

  // Client-side filtering
  const filtered = vehicles
    .filter((v) => {
      const q = filters.search.toLowerCase();
      if (
        q &&
        !v.brand.toLowerCase().includes(q) &&
        !v.model.toLowerCase().includes(q)
      )
        return false;
      if (
        filters.location &&
        !v.location.toLowerCase().includes(filters.location.toLowerCase())
      )
        return false;
      if (filters.transmission && v.transmission !== filters.transmission)
        return false;
      return true;
    })
    .sort((a, b) => {
      if (filters.sort === "price_asc") return a.price - b.price;
      if (filters.sort === "price_desc") return b.price - a.price;
      if (filters.sort === "mileage_asc") return a.mileage - b.mileage;
      if (filters.sort === "newest")
        return new Date(b.createdAt) - new Date(a.createdAt);
      return 0;
    });

  return (
    <>
      <style>{CSS}</style>
      <Navbar />
      <HeroBanner />

      <main className="main">
        <FilterBar
          filters={filters}
          setFilters={setFilters}
          onSearch={fetchVehicles}
        />

        <section className="vitrine">
          <div className="vitrine__header">
            <h2 className="vitrine__title">Veículos disponíveis</h2>
            {!loading && !error && (
              <span className="vitrine__count">
                {filtered.length} anúncio{filtered.length !== 1 ? "s" : ""}
              </span>
            )}
          </div>

          {error && (
            <div className="state-msg state-msg--error">
              <span>⚠️</span>
              <p>{error}</p>
              <button className="btn btn--outline" onClick={fetchVehicles}>
                Tentar novamente
              </button>
            </div>
          )}

          {!error && (
            <div className="grid">
              {loading
                ? Array.from({ length: 6 }).map((_, i) => (
                    <SkeletonCard key={i} />
                  ))
                : filtered.length === 0
                ? (
                  <div className="state-msg">
                    <span>🔍</span>
                    <p>Nenhum veículo encontrado com esses filtros.</p>
                  </div>
                )
                : filtered.map((v) => <VehicleCard key={v.id} vehicle={v} />)}
            </div>
          )}
        </section>
      </main>

      <footer className="footer">
        <span>◈ AutoVitrine</span>
        <span>© {new Date().getFullYear()} — Todos os direitos reservados</span>
      </footer>
    </>
  );
}

