  .card:hover {
    transform: translateY(-4px);
    border-color: rgba(255,255,255,0.15);
    box-shadow: 0 12px 40px rgba(0,0,0,0.5);
  }
  .card__thumb {
    position: relative; width: 100%; aspect-ratio: 16/9;
    background: var(--surface2); overflow: hidden;
  }
  .card__thumb img { width: 100%; height: 100%; object-fit: cover; display: block; }
  .card__no-img {
    width: 100%; height: 100%;
    display: flex; align-items: center; justify-content: center;
    font-size: 3rem; opacity: 0.2;
  }
  .card__badge {
    position: absolute; top: 0.7rem; right: 0.7rem;
    background: rgba(0,0,0,0.6); backdrop-filter: blur(6px);
    border: 1px solid var(--border); border-radius: 6px;
    font-size: 0.72rem; padding: 0.2rem 0.55rem; color: var(--text-muted);
  }
  .card__body { padding: 1.1rem 1.25rem 1.25rem; flex: 1; display: flex; flex-direction: column; gap: 0.4rem; }
  .card__top { display: flex; align-items: baseline; justify-content: space-between; gap: 0.5rem; }
  .card__title { font-family: var(--font-head); font-size: 1.05rem; font-weight: 700; }
  .card__year { font-size: 0.78rem; color: var(--text-muted); white-space: nowrap; }
  .card__engine { font-size: 0.82rem; color: var(--text-muted); }
  .card__location { font-size: 0.82rem; color: var(--text-muted); }
  .card__stats { display: flex; gap: 1rem; margin-top: 0.2rem; }
  .card__stat { font-size: 0.8rem; color: var(--text-muted); }
  .card__footer {
    display: flex; align-items: center; justify-content: space-between;
    margin-top: auto; padding-top: 0.75rem;
    border-top: 1px solid var(--border);
  }
  .card__price { font-family: var(--font-head); font-size: 1.2rem; font-weight: 700; color: var(--accent); }

  /* SKELETON */
  @keyframes shimmer {
    0%   { background-position: -600px 0; }
    100% { background-position: 600px 0; }
  }
  .skeleton-box,
  .skeleton-line {
    background: linear-gradient(90deg, var(--surface2) 25%, var(--surface) 50%, var(--surface2) 75%);
    background-size: 600px 100%;
    animation: shimmer 1.4s infinite linear;
    border-radius: 6px;
  }
  .card--skeleton .card__thumb.skeleton-box { height: 190px; border-radius: 0; }
  .skeleton-line { height: 12px; margin: 6px 0; }
  .skeleton-line--wide { width: 80%; }
  .skeleton-line--mid  { width: 55%; }
  .skeleton-line--short{ width: 35%; }

  /* STATE MESSAGES */
  .state-msg {
    grid-column: 1 / -1;
    display: flex; flex-direction: column; align-items: center;
    gap: 0.75rem; padding: 4rem 2rem;
    color: var(--text-muted); text-align: center;
  }
  .state-msg span { font-size: 2.5rem; }
  .state-msg p { font-size: 0.95rem; }
  .state-msg--error { color: #ff6b6b; }

  /* FOOTER */
  .footer {
    border-top: 1px solid var(--border);
    display: flex; justify-content: space-between; align-items: center;
    padding: 1.5rem 2.5rem;
    color: var(--text-muted); font-size: 0.8rem;
  }
  .footer span:first-child { font-family: var(--font-head); font-weight: 700; color: var(--accent); }

  /* RESPONSIVE */
  @media (max-width: 640px) {
    .navbar { padding: 1rem 1.25rem; }
    .navbar__links { display: none; }
    .main { padding: 1.5rem 1rem 3rem; }
    .filter-bar { padding: 1rem; }
    .footer { flex-direction: column; gap: 0.5rem; text-align: center; }
  }
`;
